class TreeNode:
    def __init__(self, val=0):
        self.val = val
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, val):
        """插入节点：按照BST性质找到合适位置"""
        if not self.root:
            self.root = TreeNode(val)
            return

        node = self.root
        while True:
            if val < node.val:
                if node.left is None:
                    node.left = TreeNode(val)
                    return
                node = node.left
            else:  # 允许重复值放右子树
                if node.right is None:
                    node.right = TreeNode(val)
                    return
                node = node.right

    def search(self, val):
        """查找节点：利用有序性二分查找"""
        node = self.root
        while node:
            if val == node.val:
                return node
            node = node.left if val < node.val else node.right
        return None

    def inorder(self, node=None, result=None):
        """中序遍历：返回升序序列"""
        if result is None:
            result = []
        if node is None:
            node = self.root
        if node:
            self.inorder(node.left, result)
            result.append(node.val)
            self.inorder(node.right, result)
        return result

def delete(self, val):
    """删除节点：处理三种情况"""
    self.root = self._delete_node(self.root, val)

def _delete_node(self, root, val):
    if not root:
        return None

    # 定位待删除节点
    if val < root.val:
        root.left = self._delete_node(root.left, val)
    elif val > root.val:
        root.right = self._delete_node(root.right, val)
    else:
        # 情况1: 叶子节点或只有一个子节点
        if not root.left:
            return root.right
        if not root.right:
            return root.left

        # 情况2: 两个子节点，找后继节点（右子树最小值）
        successor = self._find_min(root.right)
        root.val = successor.val
        root.right = self._delete_node(root.right, successor.val)

    return root

def _find_min(self, node):
    """找到子树中的最小值节点"""
    while node.left:
        node = node.left
    return node
